```csharp
using System;

class Program
{
    static void Main()
    {
        const int prixRepas = 1500;
        Console.WriteLine("Bienvenue à la cantine scolaire");

        try
        {
            Console.Write("Montant donné (FCFA) : ");
            string saisie = Console.ReadLine();

            if (!double.TryParse(saisie, out double montant))
                throw new FormatException("Veuillez entrer un nombre valide.");

            if (montant < 0)
                throw new ArgumentException("Le montant ne peut pas être négatif.");

            if (montant < prixRepas)
                throw new Exception($"Argent insuffisant. Il manque {prixRepas - montant} FCFA.");

            double monnaie = montant - prixRepas;
            Console.WriteLine($"Merci ! Votre monnaie : {monnaie} FCFA");
        }
        catch (FormatException ex)
        {
            Console.WriteLine($"Erreur de format : {ex.Message}");
        }
        catch (ArgumentException ex)
        {
            Console.WriteLine($"Erreur : {ex.Message}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Erreur : {ex.Message}");
        }
        finally
        {
            Console.WriteLine("Fin de la transaction. Merci !");
        }
    }
}
