string[] notes = { "12", "quinze", "18", "", null, "9" };
int somme = 0;
int nbValides = 0;

for (int i = 0; i < notes.Length; i++)  // Correction : i < notes.Length au lieu de <=
{
    try
    {
        if (notes[i] == null || notes[i].Trim() == "")
            continue;  // ignorer les valeurs vides ou null

        int note = int.Parse(notes[i]);
        somme += note;
        nbValides++;
    }
    catch (FormatException)
    {
        Console.WriteLine($"Note invalide ignorée : '{notes[i]}'");
    }
}

if (nbValides > 0)
{
    double moyenne = (double)somme / nbValides;
    Console.WriteLine($"Moyenne sur {nbValides} notes valides : {moyenne:F2}");
}
else
{
    Console.WriteLine("Aucune note valide trouvée.");
}
